    if (ch == '/') {
        char next = fgetc(fp);
        if (next == '/')  while ((ch = fgetc(fp)) != EOF && ch != '\n');
        else if (next == '*') {
            while ((ch = fgetc(fp)) != EOF) {
                if (ch == '*' && fgetc(fp) == '/') break;
            }
        }
        else { printf("<OPERATOR, />\n"); ungetc(next, fp); }
        continue;
    }

    /* Identifier / Keyword */
    if (isalpha(ch) || ch == '_') {
        /* buffer the word, then check isKeyword() */
    }

    /* Number */
    if (isdigit(ch)) { /* buffer digits and at most one '.' */ }

    /* Operator (one or two char) */
    /* Punctuator */
}
printf("<LEXICAL ERROR, %c>\n", ch);
```

